const data = $input.item.json.body;

const startDate = new Date(data.start_date);
const endDate = new Date(data.end_date);

const diffTime = endDate - startDate;
const days = Math.ceil(diffTime / (1000 * 60 * 60 * 24)) + 1;

return {
  name: data.name,
  city: data.city,
  gender: data.gender,
  destination: data.destination,
  start_date: data.start_date,
  end_date: data.end_date,
  days: days,
  budget: data.budget,
  interests: data.interests,
  email: data.email
};

const weather = $input.item.json;
const forecastDays = weather.forecast.forecastday;

let summary = [];
for (const day of forecastDays) {
  summary.push({
    date: day.date,
    condition: day.day.condition.text,
    max_temp_c: day.day.maxtemp_c,
    min_temp_c: day.day.mintemp_c,
    chance_of_rain: day.day.daily_chance_of_rain + "%"
  });
}

const tripData = $('Code in JavaScript').item.json;

const promptText = `Create a ${tripData.days}-day itinerary for ${tripData.destination}. Budget level: ${tripData.budget}. Interests: ${tripData.interests}. Weather forecast: ${JSON.stringify(summary)}. Break each day into Morning, Afternoon, and Evening sections. Include restaurant name suggestions, approximate activity costs, and 1-2 hidden gem recommendations per day. End with a simple budget table summarizing estimated costs. Format the entire response as clean HTML (no markdown, no code blocks) suitable for embedding in an email.`;

const groqBody = {
  model: "llama-3.3-70b-versatile",
  messages: [
    { role: "system", content: "You are an expert travel planner. Create detailed, practical day-by-day itineraries formatted in clean HTML." },
    { role: "user", content: promptText }
  ]
};

return {
  destination: tripData.destination,
  email: tripData.email,
  weather_summary: summary,
  groqRequestBody: groqBody
};

const groqResponse = $input.item.json;
const itineraryHtml = groqResponse.choices[0].message.content;

const tripData = $('Code in JavaScript').item.json;
const weatherData = $('Code in JavaScript1').item.json.weather_summary;

let weatherCards = '';
for (const day of weatherData) {
  weatherCards += `
    <div style="display:inline-block; background:#f0f7ff; border-radius:12px; padding:14px 18px; margin:6px; text-align:center; min-width:130px; box-shadow:0 1px 4px rgba(0,0,0,0.08);">
      <div style="font-size:13px; color:#5b7a9d; font-weight:600;">${day.date}</div>
      <div style="font-size:14px; color:#333; margin:4px 0;">${day.condition}</div>
      <div style="font-size:16px; font-weight:700; color:#2c5f8a;">${day.max_temp_c}° / ${day.min_temp_c}°C</div>
      <div style="font-size:12px; color:#888;">🌧 ${day.chance_of_rain} rain</div>
    </div>`;
}

const fullHtml = `
<html>
<head>
<style>
  body { font-family: 'Segoe UI', Arial, sans-serif; padding: 0; margin:0; color: #2d2d2d; background:#fafafa; }
  .container { max-width: 700px; margin: 0 auto; padding: 30px; }
  .hero { background: linear-gradient(135deg, #2c5f8a, #4a90c2); color: white; padding: 40px 30px; border-radius: 16px; margin-bottom: 24px; }
  .hero h1 { margin: 0 0 8px 0; font-size: 28px; }
  .hero p { margin: 4px 0; opacity: 0.95; font-size: 15px; }
  .section-title { font-size: 20px; color: #2c5f8a; margin: 28px 0 14px 0; border-bottom: 2px solid #e0ecf5; padding-bottom: 8px; }
  .weather-row { display: flex; flex-wrap: wrap; justify-content: flex-start; }
  h2, h3, h4 { color: #2c5f8a; }
  h3 { background:#f0f7ff; padding:10px 14px; border-radius:8px; margin-top:24px; }
  p { line-height: 1.6; font-size: 14.5px; }
  table { width: 100%; border-collapse: collapse; margin-top: 12px; }
  th, td { text-align: left; padding: 10px 12px; border-bottom: 1px solid #e5e5e5; font-size: 14px; }
  th { background: #2c5f8a; color: white; }
  tr:nth-child(even) { background: #f7fafc; }
  .footer { margin-top: 40px; text-align: center; font-size: 12px; color: #999; padding: 20px; }
</style>
</head>
<body>
  <div class="container">
    <div class="hero">
      <h1>✈️ Your Trip to ${tripData.destination}</h1>
      <p>📅 ${tripData.start_date} → ${tripData.end_date} (${tripData.days} days)</p>
      <p>💰 Budget: ${tripData.budget}</p>
    </div>

    <div class="section-title">Weather Forecast</div>
    <div class="weather-row">${weatherCards}</div>

    <div class="section-title">Your Itinerary</div>
    ${itineraryHtml}

    <div class="footer">Generated automatically just for you. Have an amazing trip! 🌴</div>
  </div>
</body>
</html>
`;

return {
  name: tripData.name,
  destination: tripData.destination,
  email: tripData.email,
  fullHtml: fullHtml
};
